using System.Collections.Generic; using dk.gi.app.ejendom.tjekejerskifte.Application.Abstractions; using dk.gi.app.ejendom.tjekejerskifte.Application.Models; using Gi.Batch.Shared.Logging;
namespace dk.gi.app.ejendom.tjekejerskifte.Infrastructure.Messaging
{ public sealed class EjendomTjekEjerskifteJobPublisher : IEjendomTjekEjerskifteJobPublisher { private readonly EjendomTjekEjerskifteSettings _settings; private readonly EjendomTjekEjerskifteServiceBusSender _sender; private readonly IJobLogger _logger; public EjendomTjekEjerskifteJobPublisher(EjendomTjekEjerskifteSettings settings, EjendomTjekEjerskifteServiceBusSender sender, IJobLogger logger) { _settings = settings; _sender = sender; _logger = logger; } public EjendomTjekEjerskiftePublishResult Publish(IReadOnlyCollection<EjendomTjekEjerskifteCandidate> candidates, ResolvedServiceBusSettings resolvedServiceBusSettings) { if (candidates == null || candidates.Count == 0) return new EjendomTjekEjerskiftePublishResult(true, 0, 0, "Ingen ejendomme kvalificerede til publicering."); int published = 0; int failures = 0; int skippedWithoutBfe = 0; int delaySeconds = 0; foreach (var candidate in candidates) { if (string.IsNullOrWhiteSpace(candidate.BfeNummer)) { skippedWithoutBfe++; continue; } if (_sender.Send(candidate, resolvedServiceBusSettings, delaySeconds)) published++; else failures++; delaySeconds += _settings.QueueScheduleStepSeconds; } if (failures > 0) return new EjendomTjekEjerskiftePublishResult(false, published, skippedWithoutBfe, "Service Bus-publicering fejlede for " + failures + " ejendom(me)."); _logger.Info("Publicerede " + published + " ejendom.tjekejerskifte job(s)."); return new EjendomTjekEjerskiftePublishResult(true, published, skippedWithoutBfe, "Publicerede " + published + " tinglysningsjob(s)."); } } }
